SELECT charge_status_id, COUNT(*) AS charge_count
FROM charges
GROUP BY charge_status_id;

SELECT charge_holder_id, COUNT(charge_id) AS total_charges
FROM charge_holders_charges
GROUP BY charge_holder_id;

SELECT charge_type_name
FROM charge_types
WHERE charge_type_id = 1;

SELECT charge_id, COUNT(*) AS modification_count
FROM charge_history
GROUP BY charge_id;

SELECT charge_id, amount
FROM charges
ORDER BY amount DESC;

SELECT COUNT(*) 
FROM charge_holders 
WHERE charge_holder_type = 'bank';

SELECT asset_name 
FROM assets_under_charge 
WHERE asset_type = 'movable';
